css:
atom-text-editor .github-ConflictBlock {
  display: flex;
  align-items: center;
  margin-right: 10px;
  padding: 5px;
  cursor: default;
  color: rgba(235, 219, 178, 0.75);
}
atom-text-editor .github-ConflictBlock .github-ResolutionControls {
  flex: 1;
}
atom-text-editor .github-ConflictBlock .github-ResolutionControls button {
  margin-right: 10px;
}
atom-text-editor .github-ConflictBlock .github-ResolutionControls span {
  cursor: pointer;
}
atom-text-editor .github-SideDescription {
  font-family: system-ui;
  font-size: .9em;
}
atom-text-editor .github-ResolutionControls .icon {
  line-height: 0;
}
atom-text-editor .github-ConflictTopBlock {
  margin-top: 10px;
  border-top-left-radius: 4.5px;
  border-top-right-radius: 4.5px;
}
atom-text-editor .github-ConflictBottomBlock {
  margin-bottom: 10px;
  border-bottom-left-radius: 4.5px;
  border-bottom-right-radius: 4.5px;
}
atom-text-editor .github-ConflictOurs {
  margin-right: 10px;
  background-color: rgba(94, 69, 136, 0.15);
}
atom-text-editor .github-ConflictOurs.cursor-line {
  background-color: rgba(94, 69, 136, 0.25) !important;
}
atom-text-editor .github-ConflictOursBanner {
  margin-right: 10px;
  background-color: rgba(94, 69, 136, 0.15);
}
atom-text-editor .github-ConflictOursBanner.cursor-line {
  background-color: rgba(94, 69, 136, 0.25) !important;
}
atom-text-editor .github-ConflictOursBanner.github-ConflictUnmodifiedBanner span {
  color: rgba(94, 69, 136, 0.66) !important;
}
atom-text-editor .github-ConflictOursBlock {
  color: rgba(255, 255, 255, 0.5);
  background-color: rgba(94, 69, 136, 0.35);
}
atom-text-editor .github-ConflictOursBlock .btn {
  color: white;
  border-color: rgba(0, 0, 0, 0.15);
  border: none;
  background: #5e4588;
}
